toolUseResult.content:
/* ═══════════════════════════════════════════════════
   Profile Post Cards — Parent Container
   ═══════════════════════════════════════════════════ */
.profile-postcards-parent-container {
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 90%;
    padding: 1.5rem 1.5rem 1.25rem;
    height: fit-content;
    margin-bottom: 1rem;
    margin-top: 1rem;
    border-radius: 18px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 0.7px solid var(--bg-glass-border);
    gap: 20px;
    box-shadow: 0 1px 4px rgba(80, 60, 40, 0.04);
}
/* ═══════════════════════════════════════════════════
   Postcards Header Row
   ═══════════════════════════════════════════════════ */
.postcards-header-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
    padding: 0 0.15rem;
    border-bottom: 1px solid var(--border-card);
    padding-bottom: 0.65rem;
}

.postcards-heading {
    margin: 0;
    font-family: "Playfair Display", Georgia, serif;
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-heading);
    letter-spacing: -0.015em;
    line-height: 1;
}

.postcards-count {
    font-family: var(--font-ui);
    font-weight: 500;
    color: var(--text-muted);
    font-size: 0.85rem;
    opacity: 0.7;
}

.postcards-header-actions {
    display: flex;
    align-items: center;
    gap: 0.35rem;
}

.postcards-view-toggle-btn {
    display: flex;
    align-items: center;
    justify-content: center;
    width: 34px;
    height: 34px;
    padding: 0;
    background: transparent;
    border: 1px solid var(--border-light);
    border-radius: 10px;
    color: var(--text-muted);
    cursor: pointer;
    transition: all 0.2s ease;
}

.postcards-view-toggle-btn:hover {
    background: var(--bg-hover, rgba(0, 0, 0, 0.04));
    color: rgba(212, 168, 83, 1);
    border-color: rgba(212, 168, 83, 0.3);
    transform: translateY(-1px);
}

.postcards-view-toggle-btn.is-active {
    background: rgba(212, 168, 83, 0.1);
    color: rgba(212, 168, 83, 1);
    border-color: rgba(212, 168, 83, 0.3);
    box-shadow: 0 0 0 2px rgba(212, 168, 83, 0.08);
}

/* ═══════════════════════════════════════════════════
   Grid View
   ═══════════════════════════════════════════════════ */
.postcards-grid-view {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
    width: 100%;
}

.postcards-grid-item {
    display: flex;
    flex-direction: column;
    overflow: visible;
    cursor: pointer;
    background: var(--bg-primary);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    box-shadow: var(--shadow-card-sm);
    transition: box-shadow 0.25s ease, transform 0.25s ease, border-color 0.25s ease;
}

.postcards-grid-item:hover {
    box-shadow: 0 4px 16px rgba(80, 60, 40, 0.1), 0 1px 4px rgba(80, 60, 40, 0.06);
    transform: translateY(-2px);
    border-color: rgba(212, 168, 83, 0.15);
}

[data-theme="dark"] .postcards-grid-item:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.25);
    border-color: rgba(212, 168, 83, 0.12);
}

.postcards-grid-img-wrap {
    width: 100%;
    aspect-ratio: 4 / 3;
    overflow: hidden;
    flex-shrink: 0;
    border-top-left-radius: 12px;
    border-top-right-radius: 12px;
    background-color: var(--bg-secondary);
}

.postcards-grid-thumb {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    transition: transform 0.25s ease, opacity 0.2s ease;
}

.postcards-grid-item:hover .postcards-grid-thumb {
    transform: scale(1.04);
    opacity: 0.92;
}

.postcards-grid-body {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    padding: 0.55rem 0.65rem 0.5rem;
    flex: 1;
    min-height: 0;
}

.postcards-grid-title {
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.78rem;
    font-weight: 500;
    line-height: 1.35;
    color: var(--text-primary);
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.postcards-grid-snippet {
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.68rem;
    font-weight: 400;
    line-height: 1.45;
    color: var(--text-muted);
    opacity: 0.65;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

/* ═══════════════════════════════════════════════════
   Grid Item — Footer & Settings
   ═══════════════════════════════════════════════════ */
.postcards-grid-item {
    position: relative;
}

.postcards-grid-body-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-top: auto;
    padding-top: 0.35rem;
    border-top: 1px solid var(--border-card);
}

.postcards-grid-item .user-post-settings svg {
    width: 18px;
    height: 18px;
    opacity: 0.5;
    transition: opacity 0.2s ease;
}

.postcards-grid-item:hover .user-post-settings svg {
    opacity: 0.85;
}

.postcards-grid-item .user-post-privacy {
    display: flex;
    align-items: center;
    color: var(--text-muted);
    opacity: 0.6;
    transition: opacity 0.2s ease;
}

.postcards-grid-item:hover .user-post-privacy {
    opacity: 0.85;
}

.postcards-grid-item .post-settings-container {
    position: absolute;
    top: 50%;
    left: 50%;
    z-index: 20;
}

.postcards-grid-item .confirmation-delete-bg {
    bottom: 0;
}

/* ═══════════════════════════════════════════════════
   List View
   ═══════════════════════════════════════════════════ */
.postcards-list-view {
    display: flex;
    flex-direction: column;
    gap: 16px;
    width: 100%;
}

.profile-postcards-child-container {
    display: flex;
    width: 100%;
    position: relative;
}
.profile-postcards-loading-container {
    display: flex;
    justify-content: center;
    align-items: center;
    width: 90%;
    height: 60vh;
    margin-top: 1rem;
    border-radius: 18px;
    padding: 1rem;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 0.7px solid var(--bg-glass-border);
    color: var(--text-muted);
    font-family: var(--font-ui);
    font-weight: 500;
    font-size: 0.88rem;
    opacity: 0.75;
}

/* ═══════════════════════════════════════════════════
   Individual Profile Card
   ═══════════════════════════════════════════════════ */
.profile-postcards {
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 100%;
    min-height: fit-content;
    background-color: var(--bg-primary);
    border: 1px solid var(--border-card);
    border-radius: 14px;
    overflow: visible;
    cursor: pointer;
    box-shadow: var(--shadow-card-sm);
    transition: box-shadow 0.25s ease, border-color 0.25s ease, transform 0.2s ease;
}
.profile-postcards:hover {
    box-shadow: 0 6px 28px rgba(80, 60, 40, 0.09), 0 1px 6px rgba(80, 60, 40, 0.05);
    border-color: rgba(212, 168, 83, 0.15);
    transform: translateY(-1px);
}
[data-theme="dark"] .profile-postcards:hover {
    box-shadow: 0 6px 28px rgba(0, 0, 0, 0.25), 0 1px 6px rgba(0, 0, 0, 0.15);
    border-color: rgba(212, 168, 83, 0.12);
}
.profile-postcards .card-image-banner {
    width: 100%;
    max-height: 240px;
