/* ── Mobile top header ── Hidden on desktop ── */
.mobile-top-header{
    display: none;
}
.mobile-write-btn{
    display: none;
}

.newsfeed-header{
}
.search-shell{
    position: sticky;
    top: 0;
    z-index: 14;
    align-self: stretch;
    width: 100%;
    max-width: 100%;
}
.search-top-bar{
    position: relative;
    z-index: 12;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
    box-sizing: border-box;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-card);
}
.search-input-wrap{
    position: relative;
    display: flex;
    align-items: center;
    flex: 1;
}
.search-icon{
    position: absolute;
    left: 0.85rem;
    width: 15px;
    height: 15px;
    color: var(--text-faint);
    pointer-events: none;
    transition: color 0.25s ease, transform 0.25s ease;
}
.search-input-wrap:focus-within .search-icon{
    color: #D4A853;
    transform: scale(1.08);
}
.search-input{
    width: 100%;
    border: 1.5px solid var(--border-card);
    border-radius: 10px;
    padding: 0.6rem 0.9rem 0.6rem 2.4rem;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 450;
    letter-spacing: 0.01rem;
    color: var(--text-heading);
    background: var(--bg-secondary);
    outline: none;
    transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
}
.search-input::placeholder{
    color: var(--text-faint);
    font-weight: 400;
    letter-spacing: 0.015rem;
}
.search-input:focus{
    border-color: #D4A853;
    background: var(--bg-card);
    box-shadow:
        0 0 0 3px rgba(212, 168, 83, 0.1),
        0 2px 8px rgba(212, 168, 83, 0.06);
}
.search-clear-btn{
    border: 1.5px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 8px;
    font-family: var(--font-ui);
    font-size: 0.7rem;
    font-weight: 600;
    letter-spacing: 0.02rem;
    padding: 0.4rem 0.72rem;
    cursor: pointer;
    transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
    white-space: nowrap;
}
.search-clear-btn:hover{
    background: var(--bg-hover);
    border-color: #D4A853;
    color: #D4A853;
}
/* ── Nav row (Stories) ── */
.search-nav-row{
    display: flex;
    gap: 6px;
    padding: 0.4rem 0.75rem;
}
.search-nav-btn{
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0.35rem;
    flex: 1;
    border-radius: 999px;
    font-family: var(--font-ui);
    font-size: 0.74rem;
    font-weight: 700;
    letter-spacing: 0.01rem;
    padding: 0.48rem 0.7rem;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.15s ease, transform 0.15s ease, box-shadow 0.15s ease;
}
.search-nav-btn:active{
    transform: scale(0.97);
}
.search-nav-stories{
    border: 1.5px solid rgba(234, 179, 56, 0.35);
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
    color: #e6a817;
}
.search-nav-stories:hover{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
}
.search-nav-following{
    border: 1.5px solid rgba(234, 179, 56, 0.35);
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
    color: #e6a817;
}
.search-nav-following:hover{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
}
.search-nav-for-you{
    border: 1.5px solid rgba(234, 179, 56, 0.35);
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
    color: #e6a817;
}
.search-nav-for-you:hover{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
}
.search-nav-active{
    background: linear-gradient(135deg, rgba(234, 179, 56, 0.30), rgba(255, 204, 51, 0.22));
    box-shadow: 0 0 12px rgba(234, 179, 56, 0.2);
    border-color: rgba(234, 179, 56, 0.55);
}
.search-mode-pill{
    display: flex;
    align-items: center;
    border-radius: 8px;
    border: 1.5px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-faint);
    font-family: var(--font-ui);
    font-size: 0.65rem;
    font-weight: 650;
    letter-spacing: 0.04rem;
    text-transform: uppercase;
    padding: 0.35rem 0.6rem;
    white-space: nowrap;
}

.search-empty-state{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    padding: 2rem 0.5rem;
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 500;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
}

.search-empty-link{
    border: none;
    background: transparent;
    color: var(--accent-sage);
    font-family: var(--font-ui);
    font-size: 0.84rem;
    font-weight: 650;
    cursor: pointer;
    text-decoration: underline;
}
.search-empty-link:hover{
    opacity: 0.88;
}
.search-suggestions-dropdown{
    position: absolute;
    left: 0.75rem;
    right: 0.75rem;
    top: calc(100% - 0.15rem);
    z-index: 30;
    border: 1.5px solid var(--border-card);
    border-radius: 10px;
    background: var(--bg-elevated);
    box-shadow:
        0 8px 24px rgba(0, 0, 0, 0.1),
        0 2px 8px rgba(0, 0, 0, 0.06);
    max-height: 320px;
    overflow-y: auto;
    padding: 0.3rem 0;
    animation: searchDropdownIn 0.2s ease-out;
}
@keyframes searchDropdownIn{
    from{
        opacity: 0;
        transform: translateY(-6px);
    }
    to{
        opacity: 1;
        transform: translateY(0);
    }
}
.search-suggestion-item{
    width: 100%;
    text-align: left;
    border: none;
    background: transparent;
    cursor: pointer;
    display: flex;
    flex-direction: column;
    gap: 0.15rem;
    padding: 0.6rem 0.85rem;
    transition: background 0.15s ease;
    border-left: 2.5px solid transparent;
}
.search-suggestion-item:hover{
    background: var(--bg-pill);
    border-left-color: #D4A853;
}
.search-suggestion-title{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text-heading);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}
.search-suggestion-meta{
    font-family: var(--font-ui);
    font-size: 0.68rem;
    font-weight: 450;
    color: var(--text-faint);
    letter-spacing: 0.01rem;
}
.search-suggestion-muted{
    color: var(--text-faint);
    cursor: default;
    border-left-color: transparent !important;
}
.postcards-parent-container{
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 100%;
    margin-bottom: 1rem;
    gap: 16px;
    padding: 0 16px;
    box-sizing: border-box;
}
.postcards-parent-loading-container{
    position: relative;
    top: 90px;
    display: flex;
    justify-content: center;
    align-items: center;
    flex-direction: column;
    width: 100%;
    height: 100vh;
}
.loading-newsfeed-bg{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    height: 100%;
}
.jounral-view-image{
    width: 400px;
    height: auto;
}
.inview{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 100%;
    min-height: 35px;
}

/* ── Card ── */
.cards{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 99%;
    max-width: 100%;
    min-height: fit-content;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: visible;
    cursor: pointer;
    transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.cards:hover{
    box-shadow: 0 6px 24px rgba(80, 60, 40, 0.07);
    transform: translateY(-2px);
}

.bookmarked-content-message-container{
    position: absolute;
    top: 100px;
    background-color: rgb(72, 208, 135);
    color: rgb(255, 255, 255);
    font-size: 0.78rem;
    font-weight: 600;
    padding: 0.45rem 1rem;
    border-radius: 8px;
    width: fit-content;
    z-index: 11;
    transition: ease-in-out 0.2s;
}

/* ── Banner image ── */
.card-image-banner{
    width: 100%;
    max-height: 220px;
    object-fit: cover;
    display: block;
    border-bottom: 1px solid var(--border-card);
    border-radius: 12px 12px 0 0;
    transition: opacity 0.2s ease;
}
.cards:hover .card-image-banner{
    opacity: 0.95;
}

/* ── Card content area ── */
.card-content{
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
    width: 100%;
    padding: 1rem 1.15rem 0.6rem 1.15rem;
    box-sizing: border-box;
}

/* ── User info row ── */
.user-info{
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.user-info-child-container{
    display: flex;
    align-items: center;
    height: 100%;
    gap: 0.4rem;
    width: fit-content;
}
.user-avatar-container{
    display: flex;
    align-items: center;
    justify-content: center;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
}
.user-info-avatar{
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.user-avatar-container.avatar-ring-legend{
    border-radius: 50%;
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: glow-legend 2s ease-in-out infinite alternate;
}
.user-avatar-container.avatar-ring-og{
    border-radius: 50%;
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: glow-og 2s ease-in-out infinite alternate;
}

@keyframes glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}
.user-name-container{
    display: flex;
    align-items: center;
    gap: 0.2rem;
}
.user-newsfeed-name{
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    letter-spacing: 0.005rem;
    margin: 0;
    padding: 0;
    cursor: pointer;
    color: var(--text-secondary);
    transition: color 0.15s ease;
}
.user-newsfeed-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.name-info-separator{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    color: var(--text-separator);
    font-size: 0.4rem;
    user-select: none;
}
.user-info-email-container{
    display: none;
}
.user-info-email{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-date-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
}
.user-post-privacy{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
    color: var(--text-heading);
}
.user-post-date{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-settings{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-self: flex-end;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
    user-select: none;
    color: var(--text-heading);
}
.setting-modal{
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 25px;
    bottom: 10px;
    width: 200px;
    height: 100px;
    border-radius: 10px;
    z-index: 200;
    background-color: var(--bg-elevated);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    border: 1px solid var(--border-card);
}

/* ── Content (title + text) ── */
.content-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    user-select: none;
    gap: 0.5rem;
}
.feed-text-content-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.35rem;
}
.feed-title-content{
    display: flex;
    justify-content: center;
    align-items: center;
}

.feed-title{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.45;
    letter-spacing: -0.025rem;
    color: var(--text-heading);
}
.feed-text-content{
    padding: 0;
    margin: 0;
    font-family: var(--font-serif);
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.7;
    font-size: 0.88rem;
    letter-spacing: 0.005rem;
}


/* ── Icon bar ── */
.card-icons-container{
    display: flex;
    flex-wrap: wrap;
    width: 100%;
    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
    min-height: 22px;
    align-items: center;
    justify-content: flex-start;
    gap: 0.5rem;
    box-sizing: border-box;
    border-top: 1px solid var(--border-card);
}
#card-icons{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.35rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
#card-icons-view{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.1rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
.card-icons{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
}
.icon-container{
    display: flex;
    justify-content: center;
    align-items: center;
}
.icon-container p{
    font-family: var(--font-ui);
}

.like-button:hover .svg-like path{
    fill: rgb(255, 116, 116);
}
.like-button:hover{
    background-color: rgba(255, 161, 161, 0.12);
}
.comment-button:hover{
    background-color: rgba(212, 168, 83, 0.12);
}
.comment-button:hover .svg-comment path{
    fill: var(--accent-amber);
}
.bookmark-button:hover{
    background-color: rgba(245, 158, 11, 0.12);
}
.bookmark-button:hover .svg-bookmark path{
    fill: var(--accent-amber);
}

/* ── Reading time pill ── */
.reading-time-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.7rem;
    background-color: var(--bg-pill);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    margin-left: auto;
}
.reading-time-text{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 550;
    color: var(--accent-sage);
    letter-spacing: 0.01rem;
}

/* ── Repost card ── */
.repost-header-badge{
    display: flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 1.15rem 0;
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-header-name{
    font-weight: 650;
    color: var(--text-secondary);
    cursor: pointer;
}
.repost-header-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.repost-caption-text{
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.88rem;
    font-weight: 450;
    color: var(--text-heading);
    line-height: 1.6;
    white-space: pre-wrap;
    word-break: break-word;
}
.repost-embedded-card{
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.75rem;
    background: var(--bg-secondary);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    cursor: pointer;
    transition: border-color 0.2s ease, box-shadow 0.2s ease;
}
.repost-embedded-card:hover{
    border-color: var(--accent-sage);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.06);
}
.repost-embedded-author{
    display: flex;
    align-items: center;
    gap: 0.35rem;
}
.repost-embedded-avatar{
    width: 18px;
    height: 18px;
    border-radius: 50%;
    object-fit: cover;
}
.repost-embedded-name{
    font-family: var(--font-ui);
    font-size: 0.74rem;
    font-weight: 600;
    color: var(--text-secondary);
}
.repost-embedded-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 0.92rem;
    font-weight: 650;
    color: var(--text-heading);
    line-height: 1.35;
}
.repost-embedded-text{
    margin: 0;
    font-family: var(--font-serif);
    font-size: 0.8rem;
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.55;
}
.repost-unavailable{
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 1.5rem;
    background: var(--bg-secondary);
    border: 1px dashed var(--border-card);
    border-radius: 10px;
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    color: var(--text-faint);
}
.repost-button:hover{
    background-color: rgba(72, 208, 135, 0.12);
}
.repost-button:hover .svg-repost path{
    fill: var(--accent-sage);
}
.repost-toast{
    position: fixed;
    bottom: 2rem;
    left: 50%;
    transform: translateX(-50%);
    z-index: 1000;
    padding: 0.5rem 1.2rem;
    background: var(--accent-sage);
    color: #fff;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    border-radius: 8px;
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.15);
}

.sample-content-show{
    width: 100%;
    height: 100%;
    background-color: var(--bg-primary);
    z-index: 10;
}

/* ── Mobile responsive ── */
@media (max-width: 480px){

    /* ── Mobile top header ── */
    .mobile-top-header{
        display: flex;
        align-items: center;
        justify-content: space-between;
        position: sticky;
        top: 0;
        z-index: 122;
        width: 100%;
        padding: 0.65rem 0.75rem;
        box-sizing: border-box;
        background: var(--bg-primary);
        border-bottom: 1px solid var(--border-card);
    }
    .mobile-brand-text{
        font-family: 'Playfair Display', serif;
        font-size: 1.4rem;
        font-weight: 700;
        color: var(--text-heading);
        letter-spacing: -0.02rem;
    }
    .mobile-header-profile-btn{
        display: flex;
        align-items: center;
        justify-content: center;
        background: none;
        border: 1.5px solid var(--border-card);
        border-radius: 50%;
        padding: 0;
        cursor: pointer;
        -webkit-tap-highlight-color: transparent;
        transition: border-color 0.2s ease;
    }
    .mobile-header-profile-btn:active{
        border-color: #D4A853;
    }
    .mobile-header-profile-btn img{
        width: 30px;
