/* ── Interest Sections: horizontal scroll cards ── */
.interest-sections{
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
    padding: 0.5rem 0;
}

.interest-section{
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.interest-section-header{
    display: flex;
    align-items: center;
    padding: 0 0.85rem;
}

.interest-section-title{
    font-family: var(--font-ui);
    font-size: 0.72rem;
    font-weight: 700;
    letter-spacing: 0.03rem;
    text-transform: uppercase;
    color: var(--text-secondary);
}

/* ── Horizontal scroll track ── */
.interest-section-scroll{
    display: flex;
    gap: 0.75rem;
    overflow-x: auto;
    scroll-snap-type: x mandatory;
    -webkit-overflow-scrolling: touch;
    padding: 0.25rem 0.85rem 0.5rem 0.85rem;
    scrollbar-width: none;
    -ms-overflow-style: none;
}
.interest-section-scroll::-webkit-scrollbar{
    display: none;
}

/* ── Card ── */
.interest-card{
    flex: 0 0 220px;
    scroll-snap-align: start;
    display: flex;
    flex-direction: column;
    border-radius: 12px;
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    overflow: hidden;
    cursor: pointer;
    transition: transform 0.18s ease, box-shadow 0.18s ease;
}
.interest-card:hover{
    transform: translateY(-2px);
    box-shadow: 0 4px 16px rgba(0,0,0,0.1);
}
.interest-card:active{
    transform: scale(0.98);
}

/* ── Card image ── */
.interest-card-image{
    width: 100%;
    height: 110px;
    overflow: hidden;
}
.interest-card-image img{
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* ── Card body ── */
.interest-card-body{
    display: flex;
    flex-direction: column;
    gap: 0.3rem;
    padding: 0.6rem 0.7rem 0.7rem;
}

.interest-card-title{
    font-family: var(--font-heading, var(--font-ui));
    font-size: 0.82rem;
    font-weight: 650;
    line-height: 1.3;
    color: var(--text-primary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-excerpt{
    font-family: var(--font-body, var(--font-ui));
    font-size: 0.72rem;
    line-height: 1.4;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-meta{
    display: flex;
    align-items: center;
    gap: 0.3rem;
    font-family: var(--font-ui);
    font-size: 0.65rem;
    color: var(--text-faint);
    margin-top: 0.15rem;
}

.interest-card-author{
    font-weight: 600;
}

.interest-card-dot{
    opacity: 0.5;
}

/* ── Mobile ── */
@media(max-width: 600px){
    .interest-card{
        flex: 0 0 180px;
    }
    .interest-card-image{
        height: 90px;
    }
    .interest-card-body{
        padding: 0.5rem 0.55rem 0.6rem;
    }
    .interest-card-title{
        font-size: 0.76rem;
    }
    .interest-card-excerpt{
        font-size: 0.68rem;
    }
}

