    height: 4px;
}
.interest-section-scroll::-webkit-scrollbar-track{
    background: transparent;
}
.interest-section-scroll::-webkit-scrollbar-thumb{
    background: transparent;
    border-radius: 4px;
    transition: background 0.2s ease;
}
.interest-section-scroll:hover::-webkit-scrollbar-thumb{
    background: rgba(0,0,0,0.15);
}
[data-theme="dark"] .interest-section-scroll:hover::-webkit-scrollbar-thumb{
    background: rgba(255,255,255,0.15);
}

