    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-excerpt{
    font-family: var(--font-body, var(--font-ui));
    font-size: 0.72rem;
    line-height: 1.4;
    color: var(--text-secondary);
    margin: 0;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
}

.interest-card-meta{
    display: flex;
    align-items: center;
    gap: 0.3rem;
    font-family: var(--font-ui);
    font-size: 0.65rem;
    color: var(--text-faint);
    margin-top: 0.15rem;
}

.interest-card-author{
    font-weight: 600;
}

.interest-card-dot{
    opacity: 0.5;
}

/* ── Mobile ── */
@media(max-width: 600px){
    .interest-section-scroll{
        scrollbar-width: none;
        -ms-overflow-style: none;
